import { Field as FieldPrimitive } from '@ark-ui/react/field';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { ChevronDownIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './NativeSelect.module.css';

type NativeSelectRootProps = ComponentProps<typeof FieldPrimitive.Select> & {
  controlProps?: ComponentProps<'span'>;
};

const NativeSelectRoot = forwardRef<
  ComponentRef<typeof FieldPrimitive.Select>,
  NativeSelectRootProps
>(function NativeSelectRoot({ className, controlProps, ...props }, ref) {
  return (
    <span
      {...controlProps}
      data-scope="native-select"
      data-part="control"
      data-slot="native-select-control"
      className={clsx(styles.control, normalizeClassName(controlProps?.className))}
    >
      <FieldPrimitive.Select
        {...props}
        ref={ref}
        data-slot="native-select-root"
        className={clsx(styles.root, normalizeClassName(className))}
      />
      <span
        aria-hidden="true"
        data-scope="native-select"
        data-part="indicator"
        data-slot="native-select-indicator"
        className={styles.indicator}
      >
        <ChevronDownIcon />
      </span>
    </span>
  );
});

const NativeSelect = Object.assign(NativeSelectRoot, {
  Root: NativeSelectRoot,
});

export { NativeSelect };

@layer moduix.components {
  .control {
    position: relative;
    display: inline-grid;
    width: fit-content;
    max-width: 100%;
    min-width: 0;
  }

  .root {
    box-sizing: border-box;
    width: var(--moduix-select-width, 14rem);
    max-width: var(--moduix-select-max-width, 100%);
    min-width: 0;
    height: var(--moduix-select-control-height, var(--moduix-size-md));
    margin: 0;
    border: var(--moduix-select-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-select-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-select-radius, var(--moduix-radius-md));
    padding-inline-start: var(--moduix-select-trigger-padding-x-start, var(--moduix-spacing-3));
    padding-inline-end: calc(
      var(--moduix-select-action-offset-right, var(--moduix-spacing-1)) +
        var(--moduix-select-action-size, var(--moduix-spacing-6)) +
        var(--moduix-select-trigger-padding-x-start, var(--moduix-spacing-3))
    );
    appearance: none;
    background-color: var(--moduix-select-bg, var(--moduix-color-background));
    color: var(--moduix-select-color, var(--moduix-color-foreground));
    font: inherit;
    outline: var(
        --moduix-select-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: calc(
      var(
          --moduix-select-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        ) *
        -1
    );
    cursor: pointer;
    transition:
      background-color var(--moduix-select-transition, var(--moduix-transition-default)),
      border-color var(--moduix-select-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-select-transition, var(--moduix-transition-default)),
      opacity var(--moduix-select-transition, var(--moduix-transition-default));

    &:focus-visible {
      border-color: var(--moduix-select-focus-ring-color, var(--moduix-color-ring));
      outline-color: var(--moduix-select-focus-ring-color, var(--moduix-color-ring));
    }

    &:is([data-invalid], [aria-invalid='true']) {
      border-color: var(--moduix-select-invalid-color, var(--moduix-color-destructive));
      outline-color: var(--moduix-select-invalid-color, var(--moduix-color-destructive));
    }

    &:is([data-disabled], :disabled) {
      pointer-events: none;
      opacity: var(--moduix-select-disabled-opacity, var(--moduix-opacity-disabled));
    }

    &:is([multiple], [size]:not([size='1'])) {
      height: auto;
      padding-block: var(--moduix-spacing-2);
      padding-inline: var(--moduix-select-trigger-padding-x-start, var(--moduix-spacing-3));
      appearance: auto;
    }

    @media (forced-colors: active) {
      padding-inline-end: var(--moduix-select-trigger-padding-x-start, var(--moduix-spacing-3));
      appearance: auto;
    }
  }

  .indicator {
    position: absolute;
    top: 50%;
    inset-inline-end: var(--moduix-select-action-offset-right, var(--moduix-spacing-2));
    display: inline-flex;
    width: var(--moduix-select-action-size, var(--moduix-spacing-6));
    height: var(--moduix-select-action-size, var(--moduix-spacing-6));
    align-items: center;
    justify-content: center;
    border-radius: var(--moduix-select-action-radius, var(--moduix-radius-sm));
    background: var(--moduix-select-action-bg, transparent);
    color: var(--moduix-select-icon-color, var(--moduix-color-muted-foreground));
    line-height: 0;
    pointer-events: none;
    transform: translateY(-50%);
    transition:
      background-color var(--moduix-select-transition, var(--moduix-transition-default)),
      color var(--moduix-select-transition, var(--moduix-transition-default)),
      opacity var(--moduix-select-transition, var(--moduix-transition-default));

    & > svg {
      display: block;
      width: var(--moduix-select-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-select-icon-size, var(--moduix-spacing-4));
    }

    @media (forced-colors: active) {
      display: none;
    }
  }

  .root:is([data-disabled], :disabled) + .indicator {
    opacity: var(--moduix-select-disabled-opacity, var(--moduix-opacity-disabled));
  }

  .root:not(:disabled, [data-disabled]):hover + .indicator {
    @media (hover: hover) {
      background-color: var(--moduix-select-action-bg-hover, var(--moduix-color-muted));
      color: var(--moduix-select-action-color-hover, var(--moduix-color-foreground));
    }
  }

  .root:is([multiple], [size]:not([size='1'])) + .indicator {
    display: none;
  }
}
